import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { stockStrings } from '../config';
import { stockActions } from '../actions';
import StockTaking from './StockTaking';
import { Button, FormControl } from '@material-ui/core';
import { inventoryUtil, MyTable, MyPopupMenu} from '../../utils';

const style = theme => ({
    root: {
        display : "flex"
    },
    printBtn : {
        color : inventoryUtil.getTheme().white,
        "&:hover" : {
            backgroundColor : inventoryUtil.getTheme().secondary,
            color : inventoryUtil.getTheme().white
        }
    }
})
class _StockTakingHeaderComponent extends Component {
    optionClickCallback = option => {
        const {dispatch} = this.props;
        stockActions.setSelectedStore(option)(dispatch);
        stockActions.getStoreStock(option._id, null, StockTaking.rows)(dispatch);
    }
    render() {
        const {
            classes,
            [stockStrings.selectedStore] : selectedStore,
            [stockStrings.stores] : stores,
        } = this.props;
        return (
            <div className={classes.root}>
                <MyPopupMenu
                    buttonName="stores"
                    buttonValue={selectedStore ? selectedStore.name : "Stores" }
                    options={stores}
                    optionNameProp="name"
                    optionValueProp="_id"
                    optionClickCallback={this.optionClickCallback.bind(this)}
                    />
                <div style={{display : "flex", flexGrow : 1}}/>
                <FormControl style={{margin : 10}}>
                    <Button className={classes.printBtn}>Print</Button>
                </FormControl>
            </div>
        );
    }
}


_StockTakingHeaderComponent.propTypes = {
    classes : PropTypes.object.isRequired
};
const mapStateToProps = ({stockReducer}) => ({
    [stockStrings.selectedStore] : stockReducer[stockStrings.selectedStore],
    [stockStrings.stores]  : stockReducer[stockStrings.stores],
})


export const StockTakingHeaderComponent = connect(mapStateToProps)(withStyles(style)(_StockTakingHeaderComponent));
export {StockTakingHeaderComponent as default}